import axios from 'axios';
import { Project, CoverageReport, UploadResponse } from '../types';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:3001/api';

const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

export const projectApi = {
  getAll: () => api.get<Project[]>('/projects'),
  getById: (id: number) => api.get<Project>(`/projects/${id}`),
  create: (data: Omit<Project, 'id' | 'createdAt' | 'updatedAt'>) => 
    api.post<Project>('/projects', data),
  update: (id: number, data: Partial<Project>) => 
    api.put<Project>(`/projects/${id}`, data),
  delete: (id: number) => api.delete(`/projects/${id}`),
};

export const coverageApi = {
  getByProject: (projectId: number) => 
    api.get<CoverageReport[]>(`/coverage/project/${projectId}`),
  getById: (id: number) => api.get<CoverageReport>(`/coverage/${id}`),
  getLatest: (projectId: number) => 
    api.get<CoverageReport>(`/coverage/project/${projectId}/latest`),
  getTrend: (projectId: number, days: number = 30) => 
    api.get<CoverageReport[]>(`/coverage/project/${projectId}/trend?days=${days}`),
  getFileCoverage: (reportId: number, filePath: string) => 
    api.get(`/coverage/${reportId}/file?path=${encodeURIComponent(filePath)}`),
};

export const uploadApi = {
  uploadCoverage: (formData: FormData) => 
    api.post<UploadResponse>('/upload/coverage', formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
      },
    }),
};

export default api;
